const days=['domingo','segunda','terça','quarta','quinta','sexta','sábado'];
const now=new Date(new Date().toLocaleString('en-US',{timeZone:'America/Sao_Paulo'}));
const pad=n=>String(n).padStart(2,'0');

// Horário atual em São Paulo
const horaAtual=`${pad(now.getHours())}:${pad(now.getMinutes())}`;
const dataAtual=`${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

let r=`Agora são ${horaAtual} de ${days[now.getDay()]} ${pad(now.getDate())}/${pad(now.getMonth()+1)}/${String(now.getFullYear()).slice(2)}.\n`;
r+=`Timezone: America/Sao_Paulo (UTC-03:00)\n`;
r+=`Timestamp atual: ${dataAtual}T${horaAtual}:00-03:00\n\n`;

for(let i=1;i<=10;i++){
  const f=new Date(now); f.setDate(now.getDate()+i);
  const iso=`${f.getFullYear()}-${pad(f.getMonth()+1)}-${pad(f.getDate())}`;
  if(i===1) r+=`Amanhã é ${days[f.getDay()]} ${pad(f.getDate())}/${pad(f.getMonth()+1)} → usar ${iso}T[HH:MM]:00-03:00\n`;
  else if(i===2) r+=`Depois de amanhã é ${days[f.getDay()]} ${pad(f.getDate())}/${pad(f.getMonth()+1)} → usar ${iso}T[HH:MM]:00-03:00\n`;
  else r+=`${days[f.getDay()]} será dia ${pad(f.getDate())}/${pad(f.getMonth()+1)} → usar ${iso}T[HH:MM]:00-03:00\n`;
}
return [{json:{resultado:r.trim()}}];

// ADR-003: fail-fast — não aceitar inputs incompletos
const trig = $('When_Executed_by_Another_Workflow').first().json;
const missing = [];
if (!trig.profissional_nome || String(trig.profissional_nome).trim() === '') missing.push('profissional_nome');
if (!trig.calendar_id || String(trig.calendar_id).trim() === '') missing.push('calendar_id');
if (missing.length) {
  throw new Error('agent.scheduling: inputs obrigatórios ausentes: ' + missing.join(', ') + '. Callers devem passar pelo router system.main para resolver profissional e calendar_id antes de invocar este workflow. Ver DOCS/decisions/003-bypass-fix.md');
}
// passthrough: preserva resultado do node anterior (proximos_dias → resultado)
return [{ json: $input.first().json }];
